class Solution {
public:
    long long maxGCDScore(vector<int>& nums, int k) {
        int n = nums.size();
        int max_score = 1;
        for (int i = 0; i < n - k; i++) {
            int gcd_score = 1;
            for (int j = i; j < n; j++) {
                gcd_score *= (nums[j] * nums[j + 1] * ... * nums[n - 1];
                max_score = max(max_score, gcd_score);
            }
        }
        return max_score;
    }
};
